    hotTTL: 60 * (1 + ckneMap[tenant]), // 1-2 minutes based on CKNE
    warmTTL: 300 * (1 + ckneMap[tenant] * 2), // 5-15 minutes
    coldTTL: 1800 * (1 + ckneMap[tenant] * 3) // 30-90 minutes
