// Example control logic sketch (pseudo)
type TenantState = { id:string; ckne:string; queue:number; sla:'high'|'medium'|'low'; mode:'OPEN'|'HALF'|'CLOSED' };
function tick(states:TenantState[]) {
  for (const s of states){
    const th = s.sla==='high'? 100: s.sla==='medium'? 60: 40;
    if (s.ckne === 'red' || s.queue > th) s.mode = 'OPEN';
    else if (s.ckne === 'yellow') s.mode = 'HALF';
    else s.mode = 'CLOSED';
  }
}
```

