Implement a CKNE-aware inference scheduler that maps CKNE to per-tenant model size (tiny/medium/large), batch size, and accelerator (GPU/TPU/CPU). A minute-by-minute rebalancing loop adjusts resource shares, prioritizing high-CKNE tenants while preserving SLA and preventing starvation.

```javascript
function selectResources(ckne) {
  const model = ckne > 0.75 ? 'large' : ckne > 0.25 ? 'medium' : 'tiny';
  const batchSize = ckne > 0.75 ? 32 : ckne > 0.25 ? 16 : 4;
  const accelerator = ckne > 0.75 ? 'TPU' : ckne > 0.5 ? 'GPU' : 'CPU';
  return { model, batchSize, accelerator };
}

function getAcceleratorBudget() {
  return acceleratorPool.getAvailableUnits();
}

function computeShares(tenant, accelerator, batchSize) {
  const weight = tenant.ckne * accelerator.weightFactor;
  return { gpuUnits: weight * batchSize, tenantId: tenant.id };
}

function rebalanceLoop(tenants) {
  const sorted = [...tenants].sort((a, b) => b.ckne - a.ckne);
  const totalBudget = getAcceleratorBudget();
  let allocated = 0;

  for (const tenant of sorted) {
    const { model, batchSize, accelerator } = selectResources(tenant.ckne);
    const shares = computeShares(tenant, accelerator, batchSize);

    if (allocated + shares.gpuUnits <= totalBudget) {
      tenant.allocate(shares);
      allocated += shares.gpuUnits;
    } else {
      tenant.allocateFallback(); // CPU fallback for over-budget tenants
    }
  }

  enforceMinSLA(tenants);
  return allocated / totalBudget;
}
```

**Example:** `payload: {'tenant':'A','ckne':0.72,'request':'text-classify'}` → medium model, batch size 16, GPU allocation

