questions.answer:
Design an API gateway throttling system for a shared REST gateway using CKNE (Customer Key Number Evaluation) - a tenant trust scoring system that determines priority and capacity allocation.

## Core Concepts

**CKNE (Customer Key Number Evaluation)**
- A trust score (0-1) computed from tenant behavior metrics
- Factors: request patterns, error rates, latency, abuse history, contract value
- Higher CKNE = more trusted = higher burst allowance

**Token Bucket Per Tenant**
- Each tenant has independent baseline and burst buckets
- Baseline: guaranteed minimum requests per minute (SLA)
- Burst: dynamic allowance based on CKNE and available shared capacity

**Shared Pool**
- Unused capacity is pooled and redistributed
- Prioritized to high-CKNE tenants
- Ensures efficient resource utilization

**Fairness Guarantees**
- Minimum SLA: every tenant receives baseline quota
- No starvation: low-CKNE tenants retain baseline access

## Implementation

```javascript
class CKNETokenBucket {
  constructor(config = {}) {
    this.baselineRate = config.baselineRate || 100;
    this.maxBurstMultiplier = config.maxBurstMultiplier || 5;
    this.sharedPoolSize = config.sharedPoolSize || 1000;
    this.refillInterval = config.refillInterval || 60000;
    this.tenants = new Map();
    this.ckneHistory = new Map();
  }

  calculateCKNE(tenantId) {
    const history = this.ckneHistory.get(tenantId) || {
      errorRate: 0,
      avgLatency: 0,
      abuseCount: 0,
      requestCount: 0
    };

    const errorFactor = Math.max(0, 1 - history.errorRate * 10);
    const latencyFactor = Math.max(0, 1 - history.avgLatency / 1000);
    const abuseFactor = Math.max(0, 1 - history.abuseCount * 0.2);

    return Math.min(1, (errorFactor + latencyFactor + abuseFactor) / 3);
  }

  initializeTenant(tenantId, ckne = 0.5) {
    const baseline = this.baselineRate;
    const burstCapacity = Math.floor(baseline * (this.maxBurstMultiplier - 1) * ckne);

    this.tenants.set(tenantId, {
      ckne,
      baseline,
      baselineTokens: baseline,
      burstTokens: burstCapacity,
      lastRefill: Date.now(),
      totalServed: 0
    });

    return this.tenants.get(tenantId);
  }

  refillAll() {
    const tenants = Array.from(this.tenants.values());
    const totalCKNE = tenants.reduce((sum, t) => sum + t.ckne, 0);
    const availableCapacity = this.sharedPoolSize;

    let highCKNETenants = [];
    let lowCKNETenants = [];

    tenants.forEach(tenant => {
      if (tenant.ckne >= 0.5) {
        highCKNETenants.push(tenant);
      } else {
        lowCKNETenants.push(tenant);
      }
    });

    const highCKNECount = highCKNETenants.length;

    highCKNETenants.forEach(tenant => {
      const share = highCKNECount > 0 
        ? (tenant.ckne / totalCKNE) * availableCapacity 
        : 0;
      tenant.burstTokens = Math.floor(share);
      tenant.baselineTokens = tenant.baseline;
      tenant.lastRefill = Date.now();
    });

    lowCKNETenants.forEach(tenant => {
      tenant.burstTokens = 0;
      tenant.baselineTokens = tenant.baseline;
      tenant.lastRefill = Date.now();
    });
  }

  tryConsume(tenantId, path = '/') {
    let tenant = this.tenants.get(tenantId);

    if (!tenant) {
      const ckne = this.calculateCKNE(tenantId);
      tenant = this.initializeTenant(tenantId, ckne);
    }

    if (tenant.baselineTokens > 0) {
      tenant.baselineTokens--;
      tenant.totalServed++;
      return { allowed: true, source: 'baseline', remaining: tenant.baselineTokens };
    }

    if (tenant.burstTokens > 0 && tenant.ckne >= 0.5) {
      tenant.burstTokens--;
      tenant.totalServed++;
      return { allowed: true, source: 'burst', remaining: tenant.burstTokens };
    }

    return { 
      allowed: false, 
      retryAfter: this.refillInterval,
      currentCKNE: tenant.ckne 
    };
  }
}

class CKNEGateway {
  constructor(config = {}) {
    this.throttler = new CKNETokenBucket(config);
    this.requestLog = new Map();

    setInterval(() => this.throttler.refillAll(), config.refillInterval || 60000);
  }

  handleRequest(payload) {
    const { tenant, path, ckne } = payload;

    if (ckne !== undefined) {
      const tenant = this.throttler.tenants.get(tenant);
      if (tenant) {
        tenant.ckne = ckne;
      }
    }

    const result = this.throttler.tryConsume(tenant, path);

    this.logRequest(tenant, path, result.allowed);

    return {
      ...result,
      tenant,
      path,
      timestamp: Date.now()
    };
  }

  logRequest(tenantId, path, success) {
    const log = this.requestLog.get(tenantId) || [];
    log.push({ path, success, time: Date.now() });
    if (log.length > 1000) log.shift();
    this.requestLog.set(tenantId, log);
  }
}

const gateway = new CKNEGateway({
  baselineRate: 100,
  maxBurstMultiplier: 5,
  sharedPoolSize: 5000,
  refillInterval: 60000
});

const response = gateway.handleRequest({ tenant: 'A', path: '/v1/profile', ckne: 0.25 });
console.log(JSON.stringify(response, null, 2));
```

