function decideAllocations(ckneScores, totalConns) {
  // simple proportional mapping
  const ordered = Object.entries(ckneScores).sort((a,b)=> b[1]-a[1]);
  const alloc = {};
  let used = 0;
  for (const [t, ck] of ordered) {
