## Code Example

```javascript
// Lightweight per-tenant token bucket
class TenantBucket {
  constructor(rate, burst) {
    this.rate = rate; // tokens/sec
    this.burst = burst;
    this.tokens = burst;
    this.last = Date.now();
  }
  refill() {
    const now = Date.now();
    const elapsed = (now - this.last) / 1000;
    this.tokens = Math.min(this.burst, this.tokens + elapsed * this.rate);
    this.last = now;
  }
  tryConsume(n = 1) {
    this.refill();
    if (this.tokens >= n) {
      this.tokens -= n;
      return true;
    }
    return false;
  }
}
```

